INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f7485f85-moex-00081', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X1年初發行面額$100,000、票面利率10%、5年期公司債，每年6月30日及12月 31日付息。該公司債發行價格為$92,639，有效利率12%。X1年底此公司債帳面金額是多少？ （答案四捨五入至元）', '["$92,639", "$93,197", "$93,789", "$94,416"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00082', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X1年初以$27,030,000發行4年期公司債，每年底支付利息。X1年底甲公司支付利 息$1,400,000，公司債攤銷後成本為$27,251,800。則公司債發行時有效利率與X1年度利息費 用分別為何？', '["5%；$1,178,200", "5%；$1,621,800", "6%；$1,178,200", "6%；$1,621,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00083', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X9年2月1日購入一筆土地，但購入後當地發生新冠肺炎重大疫情，故該土地之 開發與興建計畫尚未進行。已發生之購買土地相關成本包含：購買土地成本為$35,000,000、 仲介佣金$700,000、為籌措購置土地資金貸款$30,000,000（貸款期間為 X9 年 2 月 1 日起 3 年、利率3%）、拆除地上老舊建築物支付$230,000、拆除舊屋廢料出售得款$68,000、設置圍 牆$500,000、整地支付$300,000、當年地價稅$22,000。則應認列之土地成本為：', '["$37,509,000", "$36,684,000", "$36,184,000", "$36,162,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00084', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年12月31日資產與負債分別為$800,000與$480,000；X2年12月31日之權益相 關項目之帳面金額如下：股本$150,000，資本公積$210,000，保留盈餘$142,600，其他權益 $88,000（貸餘），庫藏股$12,000。若甲公司X2年12月1日以$33,000處分於X1年1月1日 以$28,800 購入且分類為透過其他綜合損益按公允價值衡量之股票投資，且因透過其他綜合 損益按公允價值衡量之債券與股票投資之公允價值變動所認列之X2年度利益分別為$18,000 與$10,000。甲公司於X2年12月31日宣告X2年度之現金股利為$42,000，且預計於X3年 1月31日支付；X2年5月曾經現金減資金額為$21,000。則X2年度甲公司淨利為何？', '["$293,600", "$297,800", "$307,800", "$321,600"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00085', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X8年1月1日文具用品帳列餘額為$69,000（X8年初並未做迴轉分錄）；X8年3月 15日與9月30日分別以現金購入$12,000與$6,500文具用品，購入文具用品時，均以費用記 錄。X8年12月31日經實地盤點後，發現文具用品尚餘$36,000。X8年12月31日甲公司有 關之調整分錄為：', '["借記：文具用品$33,000", "貸記：文具用品$51,500", "借記：文具用品費用$33,000", "貸記：文具用品費用$51,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00086', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司流動比率為2：1，下列事項何者會增加流動比率？', '["以現金買回庫藏股$500,000", "以現金$2,500購買文具用品", "向供應商進貨$380,000尚未付款", "以現金償還短期借款$500,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00087', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司2個年度之股東權益報酬率由12.14%降為10.98%，經理人欲了解該比率下降之原因， 故使用杜邦公式將其拆解為淨利率*資產週轉率*資產權益比（如下表），下列敘述何者正確？ 淨利率 資產週轉率 資產權益比 X1年 4.12% 1.375 2.143 X2年 3.65% 1.471 2.045', '["淨利率下降代表資產之使用效率降低", "資產週轉率上升代表獲利能力增加", "資產權益比降低代表與權益資金相比，債務資金減少", "甲公司之資產報酬率上升"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "adf2de4936ea", "answer_pdf_sha1": "832f56bd6e48", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00088', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '重要憲政機關之職位任期必須有所限制，以便人民有機會於一定時間內，重新決定對這些機關之授權。 此為何種憲法原則之內涵？', '["多黨競爭原則", "民主正當性原則", "權力分立原則", "法治國原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00089', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依憲法及相關司法院大法官解釋，有關軍事與國防，下列敘述何者正確？', '["總統統率全國陸海空軍，全國陸海空軍須效忠總統，保護人民", "國防與軍事事項，由中央立法，地方執行之", "軍事審判機關所行使者，亦屬國家刑罰權之一種，具有司法權之性質", "現役與退役軍人，均不得兼任文官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00090', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依司法院釋字第445號解釋意旨，集會自由與言論、講學、著作及出版自由，同屬下列何者之範疇？', '["表演自由", "表現自由", "人身自由", "行為自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
